def get_global_styles() -> str:
    """
    Returns the comprehensive CSS string for the application.
    NO Indentation, NO leading/trailing newlines.
    """
    return """<style>html,body,[data-testid="stAppViewContainer"]{background-color:#050a14!important;color:#f8fafc!important;font-family:'Outfit',sans-serif!important}[data-testid="stSidebar"]{background-color:#08101e!important;border-right:1px solid rgba(255,255,255,0.1)!important}.cg-card{background:rgba(13,24,40,0.7);backdrop-filter:blur(16px);border:1px solid rgba(255,255,255,0.1);border-radius:20px;padding:24px;margin-bottom:24px;transition:all .3s cubic-bezier(.4,0,.2,1)}.cg-card:hover{border-color:rgba(99,102,241,.4);transform:translateY(-4px)}.cg-card.blue{border-left:5px solid #6366f1}.metric-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:20px;margin-bottom:32px}.metric-card{background:rgba(13,24,40,0.7);backdrop-filter:blur(16px);border:1px solid rgba(255,255,255,0.1);border-radius:18px;padding:24px;position:relative;overflow:hidden}.top-bar{position:absolute;top:0;left:0;width:100%;height:4px}.m-label{font-size:13px;color:#94a3b8;text-transform:uppercase;letter-spacing:1px}.m-value{font-size:32px;font-weight:700;margin:8px 0;color:#fff}.cg-chip{padding:6px 14px;border-radius:100px;background:rgba(255,255,255,.05);border:1px solid rgba(255,255,255,.1);font-size:11px;font-weight:600}.badge{position:absolute;top:16px;right:16px;font-size:10px;font-weight:700;padding:4px 10px;border-radius:6px;text-transform:uppercase}.badge-green{background:rgba(16,185,129,.2);color:#10b981}.badge-blue{background:rgba(99,102,241,.2);color:#6366f1}.stButton>button{background:linear-gradient(135deg,#6366f1 0%,#4f46e5 100%)!important;color:white!important;border:none!important;border-radius:12px!important;padding:12px 24px!important;font-weight:600!important}.cg-page-title{font-size:28px;font-weight:700;background:linear-gradient(90deg,#fff,#94a3b8);-webkit-background-clip:text;-webkit-text-fill-color:transparent}.journey-step{position:relative;padding-left:50px;margin-bottom:30px}.jnode{position:absolute;left:0;top:0;width:40px;height:40px;border-radius:12px;display:flex;align-items:center;justify-content:center;font-size:18px;background:#1e293b;border:1px solid rgba(255,255,255,.1)}.jnode-done{background:#10b981!important;color:#050a14!important}.jnode-active{background:#6366f1!important;color:#fff!important}</style>"""
